import{_ as d,c as a,o as e,aN as s}from"./chunks/framework.CqA5BTDU.js";const r="/kb/assets/jumpserver-01-login.C5YP_A28.png",i="/kb/assets/jumpserver-02-dashboard.BTjb9FPP.png",p="/kb/assets/jumpserver-03-assets-list.gI_s32DH.png",o="/kb/assets/jumpserver-04-asset-edit-form.CPxisEjz.png",h="/kb/assets/jumpserver-05-account-list.C1XhT8dP.png",n="/kb/assets/jumpserver-06-permission-list.C7Y0Ngt9.png",l="/kb/assets/jumpserver-07-permission-edit.C0pDBbN2.png",c="/kb/assets/jumpserver-08-luna-asset-tree.B4GCn_lh.png",b="/kb/assets/jumpserver-09-luna-connect-dialog.-ForPEhM.png",u="/kb/assets/jumpserver-10-terminal-verify.NZ4mbd0N.png",k="/kb/assets/jumpserver-11-no-account-dialog.uOIykmPV.png",S=JSON.parse('{"title":"堡垒机与访问审计","description":"","frontmatter":{},"headers":[],"relativePath":"03.远程运维/02-堡垒机与访问审计.md","filePath":"03.远程运维/02-堡垒机与访问审计.md","lastUpdated":null}'),g={name:"03.远程运维/02-堡垒机与访问审计.md"};function m(y,t,C,v,F,_){return e(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="堡垒机与访问审计" tabindex="-1">堡垒机与访问审计 <a class="header-anchor" href="#堡垒机与访问审计" aria-label="Permalink to &quot;堡垒机与访问审计&quot;">​</a></h1><p>堡垒机把对服务器的远程访问集中到一个入口：人员登录堡垒机，再由堡垒机连接目标资产。这样做的好处是——谁、在什么时间、通过什么账号、对哪台机器、做了什么，这条路可以完整地串起来。</p><h2 id="一、直接-ssh-有什么问题" tabindex="-1">一、直接 SSH 有什么问题 <a class="header-anchor" href="#一、直接-ssh-有什么问题" aria-label="Permalink to &quot;一、直接 SSH 有什么问题&quot;">​</a></h2><p>小环境里直接 SSH 到服务器很方便：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@192.168.10.129</span></span></code></pre></div><p>但机器和人员数量上去以后，几个问题会很快暴露：</p><table tabindex="0"><thead><tr><th>问题</th><th>直接 SSH 时的典型状态</th></tr></thead><tbody><tr><td>谁能登录哪台机器</td><td>靠每台服务器上的本地账号和口头约定维持</td></tr><tr><td>谁用了哪个系统账号</td><td>多人共用 root，操作分不清是谁做的</td></tr><tr><td>谁在什么时间做了什么</td><td>翻目标机日志才知道，而且命令级别的记录不完整</td></tr><tr><td>离职或权限变更</td><td>要逐台去清 key、改密码，漏一台就留一台</td></tr><tr><td>临时授权</td><td>口头答应的事，什么时候撤也不知道</td></tr><tr><td>高危命令</td><td>拦不住，出了事只能事后翻日志</td></tr></tbody></table><p>堡垒机把这些入口收回一个点：所有人先登录堡垒机，再由堡垒机去连接资产。目标机器只信任堡垒机的来源地址，普通人员不直接持有生产机器的 SSH 入口。</p><p>访问链路大概是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>运维人员 -&gt; 堡垒机 -&gt; 目标服务器</span></span></code></pre></div><p>展开来看：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户身份 -&gt; 堡垒机登录认证 -&gt; 授权规则 -&gt; 资产账号 -&gt; SSH/RDP/数据库/Web 连接 -&gt; 审计记录</span></span></code></pre></div><p>堡垒机不只是一个跳板——跳板只管&quot;能不能连过去&quot;，堡垒机还要回答&quot;谁、什么时候、用什么身份、对哪台资产、做了什么&quot;。所以它更接近远程操作的门禁加录像机。</p><h2 id="二、用户、资产、账号、授权——这几个概念不能混" tabindex="-1">二、用户、资产、账号、授权——这几个概念不能混 <a class="header-anchor" href="#二、用户、资产、账号、授权——这几个概念不能混" aria-label="Permalink to &quot;二、用户、资产、账号、授权——这几个概念不能混&quot;">​</a></h2><p>堡垒机里最容易搞混的就是这几个对象：</p><table tabindex="0"><thead><tr><th>对象</th><th>是什么</th><th>例子</th></tr></thead><tbody><tr><td>用户</td><td>登录堡垒机的人</td><td><code>admin</code>、<code>ops01</code></td></tr><tr><td>资产</td><td>被管理的目标资源</td><td><code>192.168.10.129</code> 这台 Linux 主机</td></tr><tr><td>账号</td><td>资产上的系统登录身份</td><td><code>root</code>、<code>deploy</code>、<code>mysql_admin</code></td></tr><tr><td>授权</td><td>规定谁可以用哪个账号访问哪些资产</td><td><code>admin</code> 可以用 <code>root</code> 连接 <code>192.168.10.129</code></td></tr><tr><td>审计</td><td>连接过程、命令、录像</td><td>会话录像、命令记录</td></tr></tbody></table><p>这几个对象的关系可以写成一句话：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户通过堡垒机，被授权使用某个资产账号，连接某台资产。</span></span></code></pre></div><p>只创建资产是不够的。资产只是告诉堡垒机&quot;这台机器存在&quot;；账号表示&quot;可以用什么身份登录这台机器&quot;；授权表示&quot;这个人可以使用这个身份&quot;。三块里少任何一块，最后都在连接时报错。</p><h2 id="三、jumpserver-测试环境" tabindex="-1">三、JumpServer 测试环境 <a class="header-anchor" href="#三、jumpserver-测试环境" aria-label="Permalink to &quot;三、JumpServer 测试环境&quot;">​</a></h2><p>这次测试的环境：</p><table tabindex="0"><thead><tr><th>角色</th><th>地址</th><th>说明</th></tr></thead><tbody><tr><td>JumpServer</td><td><code>192.168.10.11</code></td><td>堡垒机</td></tr><tr><td>被管理主机</td><td><code>192.168.10.129</code></td><td>Linux 测试机</td></tr><tr><td>堡垒机管理员</td><td><code>admin</code></td><td>登录 JumpServer</td></tr><tr><td>资产账号</td><td><code>root</code></td><td>连接测试机</td></tr></tbody></table><p>访问 JumpServer：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://192.168.10.11/</span></span></code></pre></div><p><img src="'+r+'" alt="JumpServer 登录页"></p><p>登录后进入控制台。控制台能看到平台里资产、用户、会话这些对象的概况。</p><p><img src="'+i+'" alt="JumpServer 控制台"></p><p>测试环境里 <code>root/123</code> 这种密码做实验省事，但只适合封闭环境。正式环境里共用 root 基本上不可接受——至少要拆个人账号、限制 sudo、开启 MFA，再配合命令审计。</p><h2 id="四、资产" tabindex="-1">四、资产 <a class="header-anchor" href="#四、资产" aria-label="Permalink to &quot;四、资产&quot;">​</a></h2><p>资产是堡垒机纳管的目标资源。Linux 主机、Windows 主机、数据库、Kubernetes 集群、Web 管理后台，都可以抽象成资产。</p><p>资产列表里能看到测试机：</p><p><img src="'+p+'" alt="资产列表"></p><p>资产列表里的关键字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td>名称</td><td>堡垒机里显示的名字，供人识别</td></tr><tr><td>地址</td><td>目标主机 IP 或域名</td></tr><tr><td>账号</td><td>已绑定到这台资产的账号数量</td></tr><tr><td>平台</td><td>Linux、Windows、数据库等类型，决定后续的连接方式和协议</td></tr><tr><td>连接性</td><td>堡垒机到目标资产的网络和协议是否可用</td></tr></tbody></table><p>展开某个资产的编辑表单，能看到更详细的配置：</p><p><img src="'+o+'" alt="资产编辑表单"></p><p>资产配置中几个容易混淆的字段：</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><code>名称</code></td><td>给人看的名字，适合体现环境、用途和地址</td></tr><tr><td><code>IP/主机</code></td><td>堡垒机连接资产时实际使用的地址</td></tr><tr><td><code>平台</code></td><td>决定后续协议类型、账号管理和连接方式</td></tr><tr><td><code>协议</code></td><td>SSH、SFTP、RDP 等，Linux 主机通常至少要有 SSH</td></tr><tr><td><code>节点</code></td><td>资产分组标签，后面可以用节点做批量授权</td></tr><tr><td><code>备注</code></td><td>写资产用途。密码、Token 这类敏感信息不应该放在备注里</td></tr></tbody></table><p>资产的名字带上地址会比较实用，比如 <code>test-rocky-192.168.10.129</code>。纯业务名虽然更好看，但排查问题的时候地址比名字更不容易搞混。</p><h2 id="五、账号" tabindex="-1">五、账号 <a class="header-anchor" href="#五、账号" aria-label="Permalink to &quot;五、账号&quot;">​</a></h2><p>账号是资产上的系统登录身份，不是堡垒机的登录用户。这个概念特别容易跟堡垒机用户搞混——登录堡垒机用的是一套身份，堡垒机帮你连接到目标资产时用的是另一套身份。</p><p>图中 <code>root</code> 账号绑定到了 <code>test-rocky-192.168.10.129</code>：</p><p><img src="'+h+'" alt="账号列表"></p><p>账号列表里 <code>密文</code> 这个状态表示 JumpServer 保存了认证凭据（密码或私钥），连接目标资产时可以代填。这样用户不需要知道目标机器的真实密码，也能通过授权来访问。</p><p>这同时也意味着堡垒机掌握了大量资产凭据。堡垒机本身就成了高价值目标——它的管理员账号、数据库备份、配置文件、密钥文件，都要按生产核心系统的标准来保护。</p><p>管理资产账号的几种方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th><th>需要注意的问题</th></tr></thead><tbody><tr><td>托管密码</td><td>连接方便，用户不需要知道真实密码</td><td>堡垒机被侵入时凭据全部暴露</td></tr><tr><td>托管私钥</td><td>适合 Linux 主机批量管理</td><td>私钥要定期轮换，轮换流程要定义清楚</td></tr><tr><td>手动输入</td><td>临时连接、或者不想托管凭据</td><td>审计仍然在，但每次输密码体验较差</td></tr><tr><td>个人账号</td><td>责任清楚，配合 sudo 使用能更精确审计</td><td>账号从入职到离职的生命周期管理会更复杂</td></tr></tbody></table><p>生产环境里比较合理的做法是用个人账号加 sudo，而不是所有人共用 root。root 保留给少数应急场景，日常操作走个人身份，这样出了事至少能追到具体的人。</p><h2 id="六、授权规则" tabindex="-1">六、授权规则 <a class="header-anchor" href="#六、授权规则" aria-label="Permalink to &quot;六、授权规则&quot;">​</a></h2><p>授权规则是把用户、资产、账号串起来的那条线。</p><p>授权列表里能看到已经配好的规则：</p><p><img src="'+n+'" alt="授权规则列表"></p><p>这条规则的含义是：<code>admin</code> 这个用户可以访问 <code>192.168.10.129</code>，并且有一个账号可以用。</p><p>展开一条授权规则的详情：</p><p><img src="'+l+'" alt="授权规则详情"></p><p>一条授权规则包含这些部分：</p><table tabindex="0"><thead><tr><th>部分</th><th>说明</th></tr></thead><tbody><tr><td>用户</td><td>哪些堡垒机用户可以使用这条授权</td></tr><tr><td>用户组</td><td>按岗位分组批量授权，比逐个用户授权更好维护</td></tr><tr><td>资产</td><td>授权到具体某台资产</td></tr><tr><td>节点</td><td>授权到资产分组，加入节点的资产自动获得授权</td></tr><tr><td>账号</td><td>允许使用哪些资产账号（root、deploy 等）</td></tr><tr><td>协议</td><td>SSH、SFTP、RDP 等</td></tr><tr><td>动作</td><td>连接、文件传输、剪贴板共享、会话分享等</td></tr><tr><td>有效期</td><td>临时授权的过期时间，到期自动失效</td></tr></tbody></table><p>授权规则不仅要看&quot;能不能连上&quot;，还要检查权限是不是太宽了：</p><table tabindex="0"><thead><tr><th>有风险的授权方式</th><th>具体问题</th></tr></thead><tbody><tr><td>所有人授权到所有资产</td><td>权限面太大，人员变动时很难收敛</td></tr><tr><td>所有账号都可用</td><td>用户可以随便选高权限账号，绕过了最小权限原则</td></tr><tr><td>永不过期的临时授权</td><td>一次临时需求变成长期持有</td></tr><tr><td>同时开放文件传输和剪贴板</td><td>数据带出风险增高——可以下载文件、粘贴数据到本地</td></tr></tbody></table><p>临时排障时经常需要高权限，事情办完后要及时收回。如果靠人记，大概率会忘掉。授权规则里设置过期时间，到期自动失效，比写在工单备注里靠谱得多。</p><h2 id="七、通过-luna-连接资产" tabindex="-1">七、通过 Luna 连接资产 <a class="header-anchor" href="#七、通过-luna-连接资产" aria-label="Permalink to &quot;七、通过 Luna 连接资产&quot;">​</a></h2><p>JumpServer 的 Web Terminal 叫 Luna。普通用户进入 Luna 后，看到的是自己被授权的那棵资产树——没有被授权的资产不显示。</p><p><img src="'+c+'" alt="Luna 资产树"></p><p>点击资产后出现连接确认弹窗：</p><p><img src="'+b+`" alt="Luna 连接弹窗"></p><p>弹窗里能看到几个关键信息：</p><table tabindex="0"><thead><tr><th>项目</th><th>当前值</th><th>含义</th></tr></thead><tbody><tr><td>协议</td><td>SSH</td><td>用 SSH 连接 Linux 主机</td></tr><tr><td>账号</td><td>root</td><td>使用资产上托管的 root 账号</td></tr><tr><td>连接方式</td><td>Web CLI</td><td>在浏览器里打开终端</td></tr><tr><td>自动登录</td><td>未勾选</td><td>下次仍然手动确认连接方式</td></tr></tbody></table><p>连接成功后在终端里验证身份和地址：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 确认当前登录到目标机后的系统用户</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 查看目标机 IP，确认没有连错资产</span></span></code></pre></div><p><img src="`+u+'" alt="终端连接验证"></p><p>结果确认当前用户是 <code>root</code>，目标地址是 <code>192.168.10.129</code>。这个确认动作虽然基础，但远程运维里值得保留——连上机器后先确认身份、主机名、IP，再动手改配置。</p><h2 id="八、审计能看什么-不能看什么" tabindex="-1">八、审计能看什么，不能看什么 <a class="header-anchor" href="#八、审计能看什么-不能看什么" aria-label="Permalink to &quot;八、审计能看什么，不能看什么&quot;">​</a></h2><p>堡垒机通常提供这几类审计能力：</p><table tabindex="0"><thead><tr><th>审计类型</th><th>能回答什么问题</th></tr></thead><tbody><tr><td>登录日志</td><td>谁在什么时间、从哪个 IP 登录了堡垒机，有没有异常来源</td></tr><tr><td>资产连接日志</td><td>谁连接了哪台资产，用了什么账号</td></tr><tr><td>命令记录</td><td>在 SSH 会话里执行了哪些命令</td></tr><tr><td>会话录像</td><td>回放完整的交互过程，适合事故复盘</td></tr><tr><td>文件传输记录</td><td>上传、下载、SFTP 操作</td></tr><tr><td>改密记录</td><td>托管账号的密码有没有按时轮换</td></tr></tbody></table><p>命令审计不等于变更管理。它更多是事后追溯，而不是事前拦截。真正降低风险的还是授权收敛、危险命令控制、操作窗口和回滚方案这些措施。</p><p>另外，命令审计也有覆盖不到的地方：</p><table tabindex="0"><thead><tr><th>场景</th><th>审计的局限</th></tr></thead><tbody><tr><td>进入交互程序</td><td><code>vim</code>、<code>mysql</code>、<code>redis-cli</code> 里具体做了什么，不一定会完整展开在命令记录里</td></tr><tr><td>执行脚本</td><td>审到的是脚本入口（<code>bash deploy.sh</code>），脚本内部做了什么要看脚本内容和执行日志</td></tr><tr><td>二进制工具</td><td>命令名能记录到（<code>iptables</code>、<code>kill</code>），具体影响了什么要结合系统日志看</td></tr><tr><td>文件传输</td><td>SFTP 的文件传输行为，终端命令记录里看不出</td></tr></tbody></table><p>所以堡垒机是远程入口治理的一个环节，不是全部。目标机器上的 sudo 日志、系统日志、应用日志、数据库审计也得贯通起来。</p><h2 id="九、mfa-和登录保护" tabindex="-1">九、MFA 和登录保护 <a class="header-anchor" href="#九、mfa-和登录保护" aria-label="Permalink to &quot;九、MFA 和登录保护&quot;">​</a></h2><p>堡垒机能连接很多资产，入口的登录认证需要比普通系统更严格。堡垒机账号密码一旦泄露，影响面比单台服务器大得多。</p><p>常见的登录保护措施：</p><table tabindex="0"><thead><tr><th>措施</th><th>说明</th></tr></thead><tbody><tr><td>MFA</td><td>密码之外再加动态验证码或硬件令牌，拿到密码也登不进来</td></tr><tr><td>强密码策略</td><td>降低弱口令被撞库的风险</td></tr><tr><td>登录失败锁定</td><td>连续输错 N 次后临时锁定，防止暴力尝试</td></tr><tr><td>来源 IP 限制</td><td>只允许办公网、VPN 或固定出口访问堡垒机入口</td></tr><tr><td>管理员账号分离</td><td>日常用的账号和堡垒机管理员账号分开，不混用</td></tr><tr><td>定期审计管理员</td><td>清除离职或转岗后残留的管理员权限</td></tr></tbody></table><p>管理员账号如果多人共用一个，审计日志虽然看起来记录了&quot;admin 做了某操作&quot;，但实际上是多个人中某一个人做的，追踪不到具体责任人。</p><h2 id="十、两个常见故障的排查" tabindex="-1">十、两个常见故障的排查 <a class="header-anchor" href="#十、两个常见故障的排查" aria-label="Permalink to &quot;十、两个常见故障的排查&quot;">​</a></h2><h3 id="_1、-看得到资产-但连不上-——没有可用账号" tabindex="-1">1、&quot;看得到资产，但连不上&quot;——没有可用账号 <a class="header-anchor" href="#_1、-看得到资产-但连不上-——没有可用账号" aria-label="Permalink to &quot;1、&quot;看得到资产，但连不上&quot;——没有可用账号&quot;">​</a></h3><p>这种状态是 Luna 里能看到资产，点击连接时提示没有可用账号。</p><p><img src="'+k+`" alt="没有可用账号的连接提示"></p><p>排查时按这个顺序——从有没有到能不能，逐步确认：</p><table tabindex="0"><thead><tr><th>检查项</th><th>要确认什么</th></tr></thead><tbody><tr><td>资产是否存在</td><td>资产列表里能不能看到目标机器</td></tr><tr><td>账号是否绑定</td><td>账号列表里是否有对应资产的账号</td></tr><tr><td>授权是否包含这个账号</td><td>授权规则在&quot;账号&quot;那栏有没有勾选这个账号</td></tr><tr><td>授权是否对当前用户生效</td><td>有效期、启用状态、用户/用户组是否匹配</td></tr><tr><td>协议是否匹配</td><td>SSH 资产需要授权规则里包含 SSH 协议</td></tr></tbody></table><p>只授权了资产但没有授权账号，就会出现&quot;看得到但连不上&quot;。这种问题从 Luna 页面看像系统故障，实际上大部分时候是授权配置没补全。</p><h3 id="_2、连接失败" tabindex="-1">2、连接失败 <a class="header-anchor" href="#_2、连接失败" aria-label="Permalink to &quot;2、连接失败&quot;">​</a></h3><p>连接失败要拆成两段看：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户 -&gt; JumpServer</span></span>
<span class="line"><span>JumpServer -&gt; 目标资产</span></span></code></pre></div><p>第一段失败，看堡垒机登录是否正常——账号状态、MFA、浏览器访问。第二段失败，看堡垒机到目标机器的网络和认证——IP 是否可达、端口是否开放、密码或密钥是否正确。</p><p>在 JumpServer 上测到目标机器的连通性：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.129</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span></span></code></pre></div><p>端口不通的话，检查目标机器防火墙和安全组。端口通了但认证失败，检查资产账号的密码、密钥和 sshd 配置。</p><h3 id="_3、审计里看不到命令" tabindex="-1">3、审计里看不到命令 <a class="header-anchor" href="#_3、审计里看不到命令" aria-label="Permalink to &quot;3、审计里看不到命令&quot;">​</a></h3><p>先确认连接是不是经过堡垒机发起的——如果用户还能绕过堡垒机直连目标机器，堡垒机当然审不到。</p><p>目标机器侧可以收敛 SSH 来源地址，只允许堡垒机连接：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INPUT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dport</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ACCEPT</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INPUT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dport</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DROP</span></span></code></pre></div><p>这段规则只允许堡垒机 <code>192.168.10.11</code> 访问 SSH 端口，其他来源一律拒绝。要注意的是，远程修改防火墙规则时，当前连接的来源、回滚方式和带外访问入口都要提前确认好——远程直接 DROP 22 并把自己关在外面的事情并不少见。通常的做法是：先加 ACCEPT 规则，确认 ACCEPT 规则生效后，再加 DROP 规则。保留一个已有的 SSH 会话作为回滚入口，再测新规则。</p><h2 id="十一、上线时要关注的几条线" tabindex="-1">十一、上线时要关注的几条线 <a class="header-anchor" href="#十一、上线时要关注的几条线" aria-label="Permalink to &quot;十一、上线时要关注的几条线&quot;">​</a></h2><p>堡垒机上线不是把 JumpServer 装起来就完工。真正费力的部分是把资产、用户、授权、审计这几条线理顺：</p><table tabindex="0"><thead><tr><th>事项</th><th>要做的</th></tr></thead><tbody><tr><td>资产来源</td><td>从 CMDB、云平台或固定资产台账同步，不靠手工长期维护</td></tr><tr><td>用户来源</td><td>对接 LDAP/AD/企业身份源，员工离职时身份在源头停掉，堡垒机侧联动失效</td></tr><tr><td>授权模型</td><td>按岗位、环境、资产节点分组授权，不逐个给用户配</td></tr><tr><td>高危权限</td><td>root、数据库管理员、生产写权限单独审批</td></tr><tr><td>审计留存</td><td>明确日志和录像保留时间，满足合规要求</td></tr><tr><td>绕行治理</td><td>目标资产只允许堡垒机或管理网段访问，降低绕过堡垒机直连的可能</td></tr><tr><td>应急入口</td><td>堡垒机如果出故障，保留受控应急登录方式</td></tr></tbody></table><p>上线后还需要定期检查两件事：目标资产是不是还能被人绕过堡垒机直连（绕行是否有效封堵），授权规则是不是长期保持过大的范围没有收敛（人员变动后权限没有回收）。前者让审计断掉，后者让误操作的影响面扩大。</p>`,106)])])}const q=d(g,[["render",m]]);export{S as __pageData,q as default};
